import{_ as n,o as s,c as a,ag as i}from"./chunks/framework.DGzMGr_a.js";const u=JSON.parse('{"title":"前端 CI/CD 与监控","description":"","frontmatter":{"title":"前端 CI/CD 与监控","difficulty":"medium","tags":["CI/CD","前端监控","Sentry","Web-Vitals"],"estimate":15},"headers":[],"relativePath":"domains/arch/qa/qa-10-cicd-monitoring.md","filePath":"domains/arch/qa/qa-10-cicd-monitoring.md","lastUpdated":1783504823000}'),l={name:"domains/arch/qa/qa-10-cicd-monitoring.md"};function o(t,e,r,c,d,p){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="问答-10-进阶-前端-ci-cd-与监控" tabindex="-1">问答 10（进阶）：前端 CI/CD 与监控 <a class="header-anchor" href="#问答-10-进阶-前端-ci-cd-与监控" aria-label="Permalink to &quot;问答 10（进阶）：前端 CI/CD 与监控&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请描述前端项目一个&quot;体面&quot;的 CI/CD 流程，以及前端监控体系（性能、错误、行为）常见的采集方式和工具。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>CI/CD 典型流程</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>push / PR</span></span>
<span class="line"><span>  ├── install &amp; cache 依赖</span></span>
<span class="line"><span>  ├── lint（eslint + prettier + stylelint）</span></span>
<span class="line"><span>  ├── typecheck（tsc --noEmit）</span></span>
<span class="line"><span>  ├── unit test（vitest / jest）</span></span>
<span class="line"><span>  ├── build（vite / webpack）</span></span>
<span class="line"><span>  ├── e2e（playwright / cypress，可选，或在夜间跑）</span></span>
<span class="line"><span>  ├── artifact 上传 / 制品仓库</span></span>
<span class="line"><span>  └── deploy（预览环境 / 生产）</span></span>
<span class="line"><span>       ├── 灰度（部分节点先发）</span></span>
<span class="line"><span>       ├── 健康检查</span></span>
<span class="line"><span>       └── 全量 / 回滚</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><ul><li><strong>PR 阶段</strong>：lint / typecheck / test / build 必过，预览环境（Vercel Preview、腾讯云静态站）自动部署给评审用。</li><li><strong>合入 main</strong>：自动发预发；打 tag 后自动发生产。</li><li><strong>回滚</strong>：产物按 hash 存 CDN，切个引用就能回；数据库/后端相关变更用 feature flag 兜底。</li></ul><p><strong>常用工具链</strong></p><ul><li>GitHub Actions / GitLab CI / Jenkins。</li><li>缓存：<code>actions/cache</code> 缓存 <code>~/.pnpm-store</code>、<code>node_modules</code>、<code>.turbo</code>。</li><li>制品：静态资源 → OSS/CDN；SSR/Node 服务 → 镜像仓库（Docker）+ k8s。</li><li>灰度：网关按用户 / 版本 hash 分流，Feature Flag（Unleash / ByteFF / Flagsmith）配合灰度百分比。</li></ul><p><strong>前端监控三大块</strong></p><p><strong>1. 性能监控</strong></p><ul><li><strong>Web Vitals</strong>：LCP / FID（新版 INP）/ CLS / TTFB，业务 SDK 用 <code>web-vitals</code> 库上报。</li><li><strong>自定义指标</strong>：白屏时间、首屏时间、路由切换耗时、API 耗时。</li><li><strong>资源加载</strong>：<code>PerformanceObserver</code> 观察 <code>resource</code>、<code>navigation</code>、<code>longtask</code>、<code>element</code>。</li><li><strong>Long Task</strong>：<code>observer.observe({ type: &#39;longtask&#39; })</code>，找出主线程卡顿。</li></ul><p><strong>2. 错误监控</strong></p><ul><li><strong>JS 错误</strong>：<code>window.onerror</code> + <code>window.addEventListener(&#39;unhandledrejection&#39;)</code>。</li><li><strong>资源加载错误</strong>：<code>window.addEventListener(&#39;error&#39;, e =&gt; ..., true)</code>（捕获阶段拿资源错误）。</li><li><strong>框架错误</strong>：React <code>ErrorBoundary</code>、Vue <code>errorHandler</code>。</li><li><strong>接口错误</strong>：拦截 axios / fetch 记录状态码、响应体、耗时。</li><li><strong>Source Map 还原</strong>：上报 minified stack + 服务端映射到源码位置（Sentry、字节 Slardar 等自建平台）。</li></ul><p><strong>3. 行为监控</strong></p><ul><li><strong>点击 / 路由 / 曝光</strong>：埋点系统（<code>data-log</code> 属性 + 全局代理，或手动埋点）。</li><li><strong>会话回放</strong>：LogRocket / rrweb 录制 DOM 变化 + 用户交互，出问题时可回看现场。</li><li><strong>用户属性</strong>：登录 ID、设备信息、AB 版本，跟每条上报一起打标签。</li></ul><p><strong>上报策略</strong></p><ul><li><strong>批量 + 空闲上报</strong>：<code>requestIdleCallback</code> / <code>sendBeacon</code>，避免影响主流程。</li><li><strong>采样</strong>：性能指标 100% 采样成本高，通常错误 100%、性能按业务分层 10~50%。</li><li><strong>卸载时兜底</strong>：<code>visibilitychange</code> / <code>pagehide</code> 事件用 <code>navigator.sendBeacon</code> 上报剩余数据。</li><li><strong>隐私合规</strong>：脱敏用户数据（手机号、身份证、token），遵守 GDPR/CCPA/《个人信息保护法》。</li></ul><p><strong>平台化</strong></p><ul><li><strong>开源自建</strong>：Sentry（错误 + 性能）、GrowingIO / Matomo（行为）、Plausible / Umami（轻量分析）。</li><li><strong>商业 / 云端</strong>：Datadog RUM、New Relic Browser、阿里 ARMS、字节 Slardar。</li></ul><h2 id="追问-1-sentry-是怎么把-minified-报错还原成源码位置的" tabindex="-1">追问 1：Sentry 是怎么把 minified 报错还原成源码位置的？ <a class="header-anchor" href="#追问-1-sentry-是怎么把-minified-报错还原成源码位置的" aria-label="Permalink to &quot;追问 1：Sentry 是怎么把 minified 报错还原成源码位置的？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>构建产物会生成 sourcemap（<code>main.hash.js.map</code>），描述 minified 位置 → 源码位置的映射。</li><li>上线前：CI 里执行 <code>sentry-cli releases files upload-sourcemaps ./dist --url-prefix &#39;~/&#39;</code>，把 sourcemap 上传到 Sentry 后端（<strong>不上到 CDN</strong>，避免暴露源码）。</li><li>运行时上报的 stack 里带 minified 文件的 URL 和行列号；Sentry 后端用对应 release 的 sourcemap 反查，得到 <code>App.tsx:123</code> 之类的源码位置。</li><li>上传后一般在 CDN 上删除 <code>.map</code> 文件（或改 <code>.map</code> 后缀，避免被搜索），只保留 Sentry 后端一份。</li><li>关键：release 名字要和产物里注入的 <code>SENTRY_RELEASE</code> 一致，否则查不到对应 sourcemap。</li></ul><h2 id="追问-2-web-vitals-里-lcp-inp-cls-各自代表什么-分别怎么优化" tabindex="-1">追问 2：Web Vitals 里 LCP / INP / CLS 各自代表什么？分别怎么优化？ <a class="header-anchor" href="#追问-2-web-vitals-里-lcp-inp-cls-各自代表什么-分别怎么优化" aria-label="Permalink to &quot;追问 2：Web Vitals 里 LCP / INP / CLS 各自代表什么？分别怎么优化？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>LCP（Largest Contentful Paint）</strong>：最大内容元素绘制时间，反映<strong>加载感知</strong>。优化： <ul><li>首屏关键资源 preload / early hints；</li><li>图片用 <code>srcset</code> + WebP/AVIF 减少大小；</li><li>关键 CSS 内联，非关键 CSS async；</li><li>CDN + HTTP/2/3；SSR / 骨架屏。</li></ul></li><li><strong>INP（Interaction to Next Paint）</strong>：交互到下次绘制的最大延迟（2024 起替代 FID），反映<strong>响应性</strong>。优化： <ul><li>拆分 long task（<code>scheduler.yield</code> / <code>requestIdleCallback</code>）；</li><li>减少主线程 JS 体积；</li><li>避免同步布局抖动（读写 DOM 分离）；</li><li>用 Web Worker 做重计算。</li></ul></li><li><strong>CLS（Cumulative Layout Shift）</strong>：累计布局偏移，反映<strong>视觉稳定</strong>。优化： <ul><li>图片、iframe 显式声明尺寸；</li><li>字体用 <code>font-display: optional / swap</code> 时预留空间；</li><li>新增元素避免 push 内容（用 transform 或占位符）；</li><li>广告位固定高度。</li></ul></li><li>三个指标都由 <code>web-vitals</code> 库上报，能追到具体页面 / 用户群体。</li></ul><h2 id="追问-3-怎么在-ci-里做-体积不回退-守门" tabindex="-1">追问 3：怎么在 CI 里做&quot;体积不回退&quot;守门？ <a class="header-anchor" href="#追问-3-怎么在-ci-里做-体积不回退-守门" aria-label="Permalink to &quot;追问 3：怎么在 CI 里做&quot;体积不回退&quot;守门？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>生产 build 后跑一次 <strong>bundle size 分析</strong>：<code>webpack-bundle-analyzer --stats.json</code> 或 Vite 的 <code>rollup-plugin-visualizer</code>，把关键 chunk 体积写入 JSON。</li><li><strong>对比基线</strong>：拿本次 PR 的体积和 main 分支的体积对比： <ul><li>CI 里用 <code>size-limit</code> / <code>bundlewatch</code> / 自建脚本，设置阈值（如 gzipped &gt; 5% 增长要求评审 approve）；</li><li>在 PR 评论区自动 diff 关键 chunk 体积、新增依赖。</li></ul></li><li>结合 Lighthouse CI（<code>@lhci/cli</code>）：把预览环境的 LCP / TBT / bundle size 也纳入 CI，阈值化。</li><li>门槛策略： <ul><li>硬阈值：超过 <code>chunkSize &gt; 500KB</code> 直接拒绝；</li><li>软阈值：变化 &gt; 3% 需要评审说明；</li><li>白名单：某些活动页允许临时豁免，评审时明确说明原因。</li></ul></li><li>定期回顾：每周/每月出体积报告，找回归源头，避免&quot;温水煮青蛙&quot;式的膨胀。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/arch/RESOURCES">工程架构 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://web.dev/articles/vitals" target="_blank" rel="noreferrer">web.dev: Web Vitals</a>：LCP、INP、CLS 定义与优化方向。</li><li><a href="https://github.com/GoogleChrome/lighthouse-ci/blob/main/docs/getting-started.md" target="_blank" rel="noreferrer">Lighthouse CI</a>：在 CI 中跑 Lighthouse、设置性能阈值与 PR 评论。</li><li><a href="https://github.com/ai/size-limit" target="_blank" rel="noreferrer">size-limit</a>：构建产物体积守门与 CI 集成，防止 bundle 回退。</li></ul>`,32)])])}const h=n(l,[["render",o]]);export{u as __pageData,h as default};
